class NoConsecutiveBlankLinesRuleReproTest {
    private val noConsecutiveBlankLinesRuleAssertThat = assertThatRule { NoConsecutiveBlankLinesRule() }

    @Test
    fun `Given a sealed class without body and consecutive blank lines at the end of file then it should not throw NPE`() {
        val code = "sealed class Hello\n\n\n"
